sections.raw_yaml:
  required_beats:
    - {id: intro, order: 1, hard_required: true}
    - {id: verify_section, order: 2, hard_required: true}
    - {id: program_pitch, order: 3, hard_required: true}
    - {id: bill_collection, order: 4, hard_required: true}
    - {id: orphaned_check, order: 5, hard_required: false}
    - {id: button_up, order: 6, hard_required: true}

  # NOTE: short calls (< 6 min) may legitimately compress these beats if
  # existing records cover qualification (see SESSION18_fd078269). Stewart
  # checks for context-justified compression vs cut-corner truncation.

# ============================================================================
# 3. INTROS  —  Opening variants (from Ion script)
# ============================================================================

triggers_and_flips:
  - {trigger: "I can't afford it", flip: "What you can't afford is your current bill"}
  - {trigger: "It's too expensive", flip: "What's expensive is NOT switching"}
  - {trigger: "I'm not interested", flip: "What you're not interested in is staying with what you have"}
  - {trigger: "$X is high", flip: "Quote their number back as the actual expense — solar replaces the expense"}

     note: "EXCEPTION: if customer wants roof replacement, route to roofing team — see cross_sell_signals.roof_replacement_planned"}
  - {id: credit_below_670_no_alternative, severity: hard}
  - {id: existing_system_broken, severity: hard}

# ============================================================================
# 16. LLM CONTEXT INJECTION  —  Shapes how the model interprets calls
# ============================================================================

  steps:
    - {question: "Do you own your system or did you lease it?", hard_dq_answers: [PPA, lease_with_no_buyout]}
    - {question: "What company did you go with originally?", hard_dq_answers: [Sunrun, Pink Solar]}
    - {question: "Do you know the size of the panels you got?", capture: panel_size_watts}
    - {question: "Is your system working?", hard_dq_answers: [not_working, broken],
       coaching_note: "We cannot service the existing system right now"}

# ============================================================================
# 8. BUTTON UP  —  Appointment confirmation protocol
# ============================================================================

primary:
  - {id: appointment_booked, type: boolean, source: setter_call}
  - {id: appointment_held, type: boolean, source: closer_or_calendar}
  - {id: appointment_qualified, type: boolean, source: closer_feedback,
     definition: "Closer confirms lead met all qualification criteria"}
  - {id: deal_closed, type: boolean, source: closer_post_appointment}

  secondary:
    - {id: customer_state_delta, type: numeric, range: [-10, 10],
       definition: "Change in customer warmth from start to end of call"}
    - {id: handoff_contract_kept, type: boolean,
       definition: "Did closer fulfill setter's promises?"}
    - {id: verify_completion_rate, type: numeric, range: [0, 1],
       definition: "Fraction of required Verify items captured"}
    - {id: cross_sell_signals_caught, type: integer,
       definition: "Cross-sell signals surfaced AND routed (e.g., roofing)"}
    - {id: scope_creep_count, type: integer,
       definition: "Instances of setter engaging in closer-tier content"}
    - {id: flip_opportunities_deployed, type: integer,
       definition: "Inversion moves actually used vs available"}

# ============================================================================
# 15. DQ RULES  —  Hard disqualifiers
# ============================================================================

coaching_principle: |
  Should sound like a friendly chat. Top setters weave these naturally;
  bottom setters check boxes mechanically.
